    input clk,
    input [3:0] addr,
    input [7:0] data_in,
    input write_en,
    output reg [7:0] data_out
);reg [7:0] mem_array [0:15]; // Declare a simple mem_array array of 16 locations

    initial begin
        // Initialize mem_array with data
        mem_array[0] = 8'h00;
        mem_array[1] = 8'h11;
        mem_array[2] = 8'h22;
        mem_array[3] = 8'h33;
